import numpy as np

class Layer:
    def __init__(self):
        self.params = {}
        self.grads = {}

    def forward(self, X):
        raise NotImplementedError

    def backward(self, dA_prev):
        raise NotImplementedError

class Dense(Layer):
    def __init__(self, n_inputs, n_neurons, weight_scale=0.01):
        super().__init__()
        self.params['W'] = weight_scale * np.random.randn(n_inputs, n_neurons)
        self.params['b'] = np.zeros((1, n_neurons))
        self.A_prev = None

    def forward(self, A_prev):
        self.A_prev = A_prev
        self.Z = np.dot(A_prev, self.params['W']) + self.params['b']
        return self.Z

    def backward(self, dZ):
        m = self.A_prev.shape[0]
        self.grads['W'] = (1/m) * np.dot(self.A_prev.T, dZ)
        self.grads['b'] = (1/m) * np.sum(dZ, axis=0, keepdims=True)
        dA_prev = np.dot(dZ, self.params['W'].T)
        return dA_prev

class Activation(Layer):
    def __init__(self, activation_type):
        super().__init__()
        self.activation_type = activation_type
        self.A = None

    def forward(self, Z):
        self.Z = Z
        if self.activation_type == "relu":
            self.A = np.maximum(0, Z)
        elif self.activation_type == "sigmoid":
            self.A = 1 / (1 + np.exp(-Z))
        elif self.activation_type == "tanh":
            self.A = np.tanh(Z)
        else:
            raise ValueError("Invalid activation type")
        return self.A

    def backward(self, dA):
        if self.activation_type == "relu":
            dZ = dA * (self.Z > 0)
        elif self.activation_type == "sigmoid":
            sigmoid = 1 / (1 + np.exp(-self.Z))
            dZ = dA * sigmoid * (1 - sigmoid)
        elif self.activation_type == "tanh":
            dZ = dA * (1 - np.tanh(self.Z)**2)
        else:
            raise ValueError("Invalid activation type")
        return dZ

class Softmax(Layer):
    def __init__(self):
        super().__init__()
        self.probs = None

    def forward(self, Z):
        exp_Z = np.exp(Z - np.max(Z, axis=1, keepdims=True))
        self.probs = exp_Z / np.sum(exp_Z, axis=1, keepdims=True)
        return self.probs

    def backward(self, Y):
        return self.probs - Y

class NeuralNetwork:
    def __init__(self, layers):
        self.layers = layers

    def forward(self, X):
        A = X
        for layer in self.layers:
            A = layer.forward(A)
        return A

    def backward(self, Y):
        dA = Y
        for layer in reversed(self.layers):
            dA = layer.backward(dA)

    def update_params(self, learning_rate):
        for layer in self.layers:
            for key, grad in layer.grads.items():
                layer.params[key] -= learning_rate * grad

    def train(self, X, Y, epochs, learning_rate, batch_size=32):
        num_examples = X.shape[0]
        for epoch in range(epochs):
            for i in range(0, num_examples, batch_size):
                X_batch = X[i:i+batch_size]
                Y_batch = Y[i:i+batch_size]

                # Forward pass
                predictions = self.forward(X_batch)

                # Backward pass
                self.backward(Y_batch)

                # Update parameters
                self.update_params(learning_rate)

            if epoch % 10 == 0:
                loss = self.calculate_loss(self.forward(X), Y)
                print(f"Epoch {epoch}, Loss: {loss}")

    def predict(self, X):
        return self.forward(X)

    def calculate_loss(self, predictions, Y):
        if len(Y.shape) == 1 or Y.shape[1] == 1: # Regression
            return np.mean((predictions - Y)**2)
        else: # Classification
            return -np.mean(np.sum(Y * np.log(predictions), axis=1))

