    # Regression Example
    X_reg = np.random.rand(100, 10)
    Y_reg = np.sum(X_reg, axis=1, keepdims=True) + np.random.randn(100, 1) * 0.1

    layers_reg = [
        Dense(10, 32),
        Activation("relu"),
        Dense(32, 1)
    ]

    model_reg = NeuralNetwork(layers_reg)
    model_reg.train(X_reg, Y_reg, epochs=100, learning_rate=0.01)

    # Classification Example
    X_class = np.random.rand(100, 10)
    Y_class = np.random.randint(0, 3, 100) # 3 classes
    Y_class_onehot = np.eye(3)[Y_class]

    layers_class = [
        Dense(10, 32),
        Activation("relu"),
        Dense(32, 3),
        Softmax()
    ]

    model_class = NeuralNetwork(layers_class)
    model_class.train(X_class, Y_class_onehot, epochs=100, learning_rate=0.01)

    predictions = model_class.predict(X_class)
    predicted_classes = np.argmax(predictions, axis=1)
    accuracy = np.mean(predicted_classes == Y_class)
    print(f"Classification Accuracy: {accuracy}")

