import numpy as np

class Neuron:
    def __init__(self, num_inputs, activation_function='sigmoid'):
        self.weights = np.random.randn(num_inputs)
        self.bias = np.random.randn()
        self.activation_function = activation_function
        self.last_input = None
        self.last_activation = None

    def activate(self, x):
        self.last_input = x
        z = np.dot(self.weights, x) + self.bias
        if self.activation_function == 'sigmoid':
            self.last_activation = self.sigmoid(z)
        elif self.activation_function == 'relu':
            self.last_activation = self.relu(z)
        elif self.activation_function == 'linear':
            self.last_activation = z
        else:
            raise ValueError("Invalid activation function")
        return self.last_activation

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(0, x)

    def relu_derivative(self, x):
        return (x > 0).astype(float)

    def linear_derivative(self, x):
        return 1

    def backward(self, output_gradient, learning_rate):
        if self.activation_function == 'sigmoid':
            activation_derivative = self.sigmoid_derivative(self.last_activation)
        elif self.activation_function == 'relu':
            activation_derivative = self.relu_derivative(self.last_activation)
        elif self.activation_function == 'linear':
            activation_derivative = self.linear_derivative(self.last_activation)
        else:
            raise ValueError("Invalid activation function")

        delta = output_gradient * activation_derivative
        weight_gradient = self.last_input * delta
        self.weights -= learning_rate * weight_gradient
        self.bias -= learning_rate * delta
        return delta * self.weights


class Layer:
    def __init__(self, num_neurons, num_inputs, activation_function='sigmoid'):
        self.neurons = [Neuron(num_inputs, activation_function) for _ in range(num_neurons)]

    def forward(self, x):
        return np.array([neuron.activate(x) for neuron in self.neurons])

    def backward(self, output_gradient, learning_rate):
        gradients = []
        for i, neuron in enumerate(self.neurons):
            gradients.append(neuron.backward(output_gradient[i], learning_rate))
        return np.sum(gradients, axis=0)


class NeuralNetwork:
    def __init__(self, layer_sizes, activation_functions=None):
        self.layers = []
        if activation_functions is None:
            activation_functions = ['sigmoid'] * (len(layer_sizes) - 1)
        if len(activation_functions) != len(layer_sizes) - 1:
            raise ValueError("Number of activation functions must be one less than number of layers")

        for i in range(len(layer_sizes) - 1):
            self.layers.append(Layer(layer_sizes[i+1], layer_sizes[i], activation_functions[i]))

    def forward(self, x):
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, output_gradient, learning_rate):
        for layer in reversed(self.layers):
            output_gradient = layer.backward(output_gradient, learning_rate)

    def train(self, X, y, learning_rate, epochs, loss_function='mse'):
        for epoch in range(epochs):
            for i in range(len(X)):
                x = X[i]
                target = y[i]
                output = self.forward(x)

                if loss_function == 'mse':
                    output_gradient = self.mse_derivative(output, target)
                elif loss_function == 'cross_entropy':
                    output_gradient = self.cross_entropy_derivative(output, target)
                else:
                    raise ValueError("Invalid loss function")

                self.backward(output_gradient, learning_rate)

            if epoch % 100 == 0:
                loss = self.calculate_loss(X, y, loss_function)
                print(f"Epoch {epoch}, Loss: {loss}")

    def predict(self, X):
        predictions = []
        for x in X:
            predictions.append(self.forward(x))
        return np.array(predictions)

    def mse(self, y_predicted, y_true):
        return np.mean((y_predicted - y_true)**2)

    def mse_derivative(self, y_predicted, y_true):
        return 2 * (y_predicted - y_true) / y_predicted.size

    def cross_entropy(self, y_predicted, y_true):
        y_predicted = np.clip(y_predicted, 1e-15, 1 - 1e-15)
        return -np.sum(y_true * np.log(y_predicted) + (1 - y_true) * np.log(1 - y_predicted))

    def cross_entropy_derivative(self, y_predicted, y_true):
        y_predicted = np.clip(y_predicted, 1e-15, 1 - 1e-15)
        return - (y_true / y_predicted) + (1 - y_true) / (1 - y_predicted)

    def calculate_loss(self, X, y, loss_function):
        loss = 0
        for i in range(len(X)):
            x = X[i]
            target = y[i]
            output = self.forward(x)
            if loss_function == 'mse':
                loss += self.mse(output, target)
            elif loss_function == 'cross_entropy':
                loss += self.cross_entropy(output, target)
        return loss / len(X)


