import numpy as np

class Neuron:
    def __init__(self, num_inputs, activation_function='sigmoid'):
        self.weights = np.random.randn(num_inputs)
        self.bias = np.random.randn()
        self.activation_function = activation_function
        self.activation = None
        self.input = None
        self.delta = None

    def activate(self, x):
        self.input = x
        z = np.dot(self.weights, x) + self.bias
        if self.activation_function == 'sigmoid':
            self.activation = self.sigmoid(z)
        elif self.activation_function == 'relu':
            self.activation = self.relu(z)
        elif self.activation_function == 'linear':
            self.activation = z
        elif self.activation_function == 'tanh':
            self.activation = self.tanh(z)
        else:
            raise ValueError("Invalid activation function")
        return self.activation

    def sigmoid(self, x):
        return 1 / (1 + np.exp(-x))

    def sigmoid_derivative(self, x):
        return x * (1 - x)

    def relu(self, x):
        return np.maximum(0, x)

    def relu_derivative(self, x):
        return (x > 0).astype(float)

    def tanh(self, x):
        return np.tanh(x)

    def tanh_derivative(self, x):
        return 1 - x**2

class Layer:
    def __init__(self, num_neurons, num_inputs, activation_function='sigmoid'):
        self.neurons = [Neuron(num_inputs, activation_function) for _ in range(num_neurons)]
        self.output = None

    def forward(self, x):
        self.output = np.array([neuron.activate(x) for neuron in self.neurons])
        return self.output

class NeuralNetwork:
    def __init__(self, layer_sizes, activation_functions=None):
        self.layers = []
        if activation_functions is None:
            activation_functions = ['sigmoid'] * (len(layer_sizes) - 1)
        if len(activation_functions) != len(layer_sizes) - 1:
            raise ValueError("Number of activation functions must be one less than number of layers")

        for i in range(len(layer_sizes) - 1):
            self.layers.append(Layer(layer_sizes[i+1], layer_sizes[i], activation_functions[i]))

    def forward(self, x):
        for layer in self.layers:
            x = layer.forward(x)
        return x

    def backward(self, x, y, learning_rate):
        output = self.forward(x)
        last_layer = self.layers[-1]
        if last_layer.neurons[0].activation_function == 'sigmoid':
            delta = (output - y) * np.array([neuron.sigmoid_derivative(neuron.activation) for neuron in last_layer.neurons])
        elif last_layer.neurons[0].activation_function == 'relu':
            delta = (output - y) * np.array([neuron.relu_derivative(neuron.activation) for neuron in last_layer.neurons])
        elif last_layer.neurons[0].activation_function == 'linear':
            delta = (output - y)
        elif last_layer.neurons[0].activation_function == 'tanh':
            delta = (output - y) * np.array([neuron.tanh_derivative(neuron.activation) for neuron in last_layer.neurons])
        else:
            raise ValueError("Invalid activation function")

        for i in reversed(range(len(self.layers))):
            layer = self.layers[i]
            for j, neuron in enumerate(layer.neurons):
                neuron.delta = delta[j]
                neuron.weights -= learning_rate * neuron.delta * neuron.input
                neuron.bias -= learning_rate * neuron.delta

            if i > 0:
                prev_layer = self.layers[i-1]
                delta = np.zeros(len(prev_layer.neurons))
                for k, prev_neuron in enumerate(prev_layer.neurons):
                    for j, neuron in enumerate(layer.neurons):
                        delta[k] += neuron.weights[k] * neuron.delta

                if prev_layer.neurons[0].activation_function == 'sigmoid':
                    delta *= np.array([neuron.sigmoid_derivative(neuron.activation) for neuron in prev_layer.neurons])
                elif prev_layer.neurons[0].activation_function == 'relu':
                    delta *= np.array([neuron.relu_derivative(neuron.activation) for neuron in prev_layer.neurons])
                elif prev_layer.neurons[0].activation_function == 'tanh':
                    delta *= np.array([neuron.tanh_derivative(neuron.activation) for neuron in prev_layer.neurons])
                else:
                    pass # No derivative needed for input layer

    def train(self, X, Y, learning_rate, epochs):
        for epoch in range(epochs):
            for i in range(len(X)):
                self.backward(X[i], Y[i], learning_rate)

    def predict(self, x):
        return self.forward(x)

